const FEE_RATIOS: Record<string, number> = {
  'anesthesiologist': 0.5, // 50% of surgeon fee
  'assistant': 0.5,        // 50% of surgeon fee
  'nurse': 0.33,           // 33% of surgeon fee
  'technician': 0.25       // 25% of surgeon fee
