    }));
  };

  const updateResource = (type: 'consumables' | 'equipment' | 'others', index: number, field: 'name' | 'cost', value: any) => {
    setCostForm(prev => {
      const updatedList = [...prev[type]];
      updatedList[index] = { 
        ...updatedList[index], 
        [field]: field === 'cost' ? (parseFloat(value) || 0) : value 
      };
      return { ...prev, [type]: updatedList };
