exports.getInpatientDetails = (req, res) => {
    const { id } = req.params;
    try {
        const admission = db.prepare(`
            SELECT 
                a.*, p.full_name as patientName, p.age, p.gender, p.blood_group as bloodGroup, p.patient_id as patientCode,
                b.room_number as roomNumber, b.cost_per_day as costPerDay,
                m.full_name as doctorName
            FROM admissions a
            JOIN patients p ON a.patient_id = p.id
            JOIN beds b ON a.bed_id = b.id
            JOIN medical_staff m ON a.doctor_id = m.id
            WHERE a.id = ?
        `).get(id);

        if(!admission) return res.status(404).json({error: "Admission not found"});

        // Calculate days stayed
        const start = new Date(admission.entry_date);
        const now = new Date();
        const diff = Math.max(1, Math.ceil(Math.abs(now - start) / (1000 * 60 * 60 * 24)));
        admission.daysStayed = diff;
        admission.estimatedBill = diff * admission.costPerDay;

        // Fetch Notes
        const notes = db.prepare(`
            SELECT n.*, m.full_name as doctorName 
            FROM inpatient_notes n
            JOIN medical_staff m ON n.doctor_id = m.id
            WHERE n.admission_id = ?
            ORDER BY n.created_at DESC
        `).all(id);

        admission.notes = notes.map(n => ({...n, vitals: JSON.parse(n.vitals || '{}')}));

        res.json(admission);
