    const { dischargeNotes, dischargeStatus } = req.body;

    try {
        const tx = db.transaction(() => {
            // 1. Get Admission Info
            const adm = db.prepare("SELECT * FROM admissions WHERE id = ?").get(id);
            const bed = db.prepare("SELECT * FROM beds WHERE id = ?").get(adm.bed_id);

            // 2. Calculate Final Bill
            const start = new Date(adm.entry_date);
            const end = new Date();
            const days = Math.max(1, Math.ceil(Math.abs(end - start) / (1000 * 60 * 60 * 24)));
            const totalCost = days * bed.cost_per_day;

            // 3. Generate Bill
            const billNumber = Math.floor(10000000 + Math.random() * 90000000).toString();
            const billInfo = db.prepare('INSERT INTO billing (bill_number, patient_id, total_amount, status) VALUES (?, ?, ?, ?)').run(billNumber, adm.patient_id, totalCost, 'pending');
            db.prepare('INSERT INTO billing_items (billing_id, description, amount) VALUES (?, ?, ?)').run(billInfo.lastInsertRowid, `Inpatient Stay (${days} days @ $${bed.cost_per_day}/day)`, totalCost);

            // 4. Update Admission & Bed & Patient
            db.prepare(`
                UPDATE admissions 
                SET status = 'discharged', discharge_date = ?, discharge_notes = ?, discharge_status = ?, bill_id = ?
                WHERE id = ?
            `).run(end.toISOString(), dischargeNotes, dischargeStatus, billInfo.lastInsertRowid, id);

            db.prepare("UPDATE beds SET status = 'available' WHERE id = ?").run(adm.bed_id);
            db.prepare("UPDATE patients SET type = 'outpatient' WHERE id = ?").run(adm.patient_id);
        });
        tx();
        res.json({success: true});
    } catch(e) { res.status(500).json({ error: e.message }); }
};
