                                 <td className="px-6 py-4 font-medium text-slate-700 dark:text-slate-300">{row.patientName}</td>
                                 <td className="px-6 py-4 text-gray-500 dark:text-slate-400">{new Date(row.date).toLocaleDateString()}</td>
                                 <td className="px-6 py-4 text-right font-bold text-gray-900 dark:text-white">${row.totalAmount}</td>
                                 <td className="px-6 py-4 text-center"><Badge color={row.status === 'paid' ? 'green' : 'red'}>{row.status}</Badge></td>
                               </>
                             )}
                             {/* Lab Rows */}
                             {recordType === 'lab' && (
                               <>
                                 <td className="px-6 py-4 text-gray-500 dark:text-slate-400">{new Date(row.created_at).toLocaleDateString()}</td>
                                 <td className="px-6 py-4 font-medium text-slate-700 dark:text-slate-300">{row.patientName}</td>
                                 <td className="px-6 py-4 text-gray-500 dark:text-slate-400">{row.testNames || 'Multiple Tests'}</td>
                                 <td className="px-6 py-4 text-center"><Badge color={row.status === 'completed' ? 'green' : 'yellow'}>{row.status}</Badge></td>
                               </>
                             )}
                          </tr>
                       ))
                    )}
                 </tbody>
              </table>
           </div>
        </Card>
      )}
    </div>
  );
};

To implement a comprehensive HR system including Payroll, Attendance, Leaves, Fines/Bonuses, and Loans, I need to update the database schema, backend logic, API routes, frontend service, and the UI.

