const Database = require('better-sqlite3');
const path = require('path');
const fs = require('fs');

const dbPath = process.env.DB_PATH || path.join(__dirname, '../../allcare.db');

// Ensure the directory exists
const dbDir = path.dirname(dbPath);
if (!fs.existsSync(dbDir)) {
  fs.mkdirSync(dbDir, { recursive: true });
}

const db = new Database(dbPath, { verbose: console.log });

const initDB = () => {
  db.pragma('journal_mode = WAL');

  // --- SMART RESET LOGIC ---
  let shouldReset = false;
  try {
    // Check if medical_staff has base_salary
    const staffTableCheck = db.prepare("SELECT name FROM sqlite_master WHERE type='table' AND name='medical_staff'").get();
    if (staffTableCheck) {
        const columns = db.pragma('table_info(medical_staff)');
        const hasBaseSalary = columns.some(col => col.name === 'base_salary');
        if (!hasBaseSalary) {
            console.log('⚠️  OUTDATED SCHEMA (Missing base_salary). Resetting database...');
            shouldReset = true;
        }
    }

    // Check if attendance table exists
    const attendanceCheck = db.prepare("SELECT name FROM sqlite_master WHERE type='table' AND name='attendance'").get();
    if (!attendanceCheck) {
        console.log('⚠️  OUTDATED SCHEMA (Missing HR tables). Resetting database...');
        shouldReset = true;
    }

  } catch (e) {
    console.log('Database check failed, proceeding with initialization.', e);
  }

  if (shouldReset) {
    const tables = [
      'users', 'patients', 'medical_staff', 'appointments', 'billing', 'billing_items',
      'lab_tests', 'lab_requests', 'nurse_services', 'operations_catalog', 'operations',
      'beds', 'admissions', 'inpatient_notes', 'departments', 'system_settings',
      'tax_rates', 'payment_methods', 'attendance', 'leaves', 'loans', 'financial_records', 'payroll'
    ];
    tables.forEach(t => db.exec(`DROP TABLE IF EXISTS ${t}`));
    console.log('✅ Database reset complete. Rebuilding tables...');
  }

  // --- SCHEMA DEFINITIONS ---
  const schema = `
    -- USERS & ROLES
    CREATE TABLE IF NOT EXISTS users (
