```javascript
const { db } = require('../config/database');

exports.getAll = (req, res) => {
  try {
    const staff = db.prepare('SELECT * FROM medical_staff ORDER BY full_name').all();
    const mapped = staff.map(s => ({
      id: s.id,
      employeeId: s.employee_id,
      fullName: s.full_name,
      type: s.type,
      department: s.department,
      specialization: s.specialization,
      baseSalary: s.base_salary || 0,
      consultationFee: s.consultation_fee,
      consultationFeeFollowup: s.consultation_fee_followup || 0,
      consultationFeeEmergency: s.consultation_fee_emergency || 0,
      isAvailable: !!s.is_available,
      email: s.email,
      phone: s.phone
    }));
    res.json(mapped);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
};

exports.create = (req, res) => {
  const { fullName, type, department, specialization, baseSalary, consultationFee, consultationFeeFollowup, consultationFeeEmergency, email, phone } = req.body;
  const prefix = type === 'doctor' ? 'DOC' : type === 'nurse' ? 'NUR' : 'STF';
  const employeeId = `${prefix}-${Math.floor(Math.random() * 10000).toString().padStart(4, '0')}`;

  try {
    const info = db.prepare(`
      INSERT INTO medical_staff (employee_id, full_name, type, department, specialization, base_salary, consultation_fee, consultation_fee_followup, consultation_fee_emergency, email, phone)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `).run(employeeId, fullName, type, department, specialization, baseSalary || 0, consultationFee || 0, consultationFeeFollowup || 0, consultationFeeEmergency || 0, email, phone);
    res.status(201).json({ id: info.lastInsertRowid, employeeId, ...req.body });
  } catch (err) {
    res.status(400).json({ error: err.message });
  }
};

exports.update = (req, res) => {
  const { id } = req.params;
  const updates = Object.keys(req.body);

  // Mapping
  const dbFields = {
    isAvailable: 'is_available',
    baseSalary: 'base_salary',
    consultationFee: 'consultation_fee',
    consultationFeeFollowup: 'consultation_fee_followup',
    consultationFeeEmergency: 'consultation_fee_emergency',
    fullName: 'full_name'
  };

  const setClause = updates.map(u => `${dbFields[u] || u} = ?`).join(', ');
  const values = updates.map(u => u === 'isAvailable' ? (req.body[u] ? 1 : 0) : req.body[u]);

  try {
    db.prepare(`UPDATE medical_staff SET ${setClause} WHERE id = ?`).run(...values, id);
    res.sendStatus(200);
  } catch (err) {
    res.status(400).json({ error: err.message });
  }
};

// --- ATTENDANCE ---
exports.getAttendance = (req, res) => {
    try {
        const { date } = req.query; // YYYY-MM-DD
        const sql = date 
            ? `SELECT a.*, m.full_name, m.employee_id FROM attendance a JOIN medical_staff m ON a.staff_id = m.id WHERE a.date = ?`
            : `SELECT a.*, m.full_name, m.employee_id FROM attendance a JOIN medical_staff m ON a.staff_id = m.id ORDER BY a.date DESC LIMIT 100`;
        const data = date ? db.prepare(sql).all(date) : db.prepare(sql).all();
        res.json(data);
    } catch(e) { res.status(500).json({error: e.message}); }
};

exports.markAttendance = (req, res) => {
    const { staffId, date, status, clockIn, clockOut } = req.body;
    try {
        // Upsert logic handled by app or replace
        const exists = db.prepare('SELECT id FROM attendance WHERE staff_id = ? AND date = ?').get(staffId, date);
        if (exists) {
            db.prepare('UPDATE attendance SET status = ?, clock_in = ?, clock_out = ? WHERE id = ?')
              .run(status, clockIn, clockOut, exists.id);
        } else {
            db.prepare('INSERT INTO attendance (staff_id, date, status, clock_in, clock_out) VALUES (?, ?, ?, ?, ?)')
              .run(staffId, date, status, clockIn, clockOut);
        }
        res.json({ success: true });
    } catch(e) { res.status(500).json({error: e.message}); }
};

// --- LEAVES ---
exports.getLeaves = (req, res) => {
    try {
        const leaves = db.prepare(`SELECT l.*, m.full_name FROM leaves l JOIN medical_staff m ON l.staff_id = m.id ORDER BY l.start_date DESC`).all();
        res.json(leaves);
    } catch(e) { res.status(500).json({error: e.message}); }
};

exports.requestLeave = (req, res) => {
    const { staffId, type, startDate, endDate, reason } = req.body;
    try {
        db.prepare('INSERT INTO leaves (staff_id, type, start_date, end_date, reason, status) VALUES (?, ?, ?, ?, ?, ?)')
          .run(staffId, type, startDate, endDate, reason, 'pending');
        res.json({ success: true });
    } catch(e) { res.status(500).json({error: e.message}); }
};

exports.updateLeaveStatus = (req, res) => {
    const { id } = req.params;
    const { status } = req.body;
    try {
        db.prepare('UPDATE leaves SET status = ? WHERE id = ?').run(status, id);
        res.json({ success: true });
    } catch(e) { res.status(500).json({error: e.message}); }
};

// --- FINANCIALS (FINES/BONUSES) ---
exports.getFinancialRecords = (req, res) => {
    try {
        const records = db.prepare(`SELECT f.*, m.full_name FROM financial_records f JOIN medical_staff m ON f.staff_id = m.id ORDER BY f.date DESC`).all();
