    const { staffId, amount, date, plan } = req.body;
    try {
        db.prepare('INSERT INTO loans (staff_id, amount, remaining_amount, request_date, repayment_plan, status) VALUES (?, ?, ?, ?, ?, ?)')
          .run(staffId, amount, amount, date, plan, 'pending');
        res.json({ success: true });
    } catch(e) { res.status(500).json({error: e.message}); }
};

exports.updateLoanStatus = (req, res) => {
