    tests.forEach(t => insertTest.run(t.name, t.category, t.cost, t.range));
  }

  // Medical Staff (Updated with Salary)
  const existingStaff = db.prepare('SELECT COUNT(*) as count FROM medical_staff').get();
  if (existingStaff.count === 0) {
    const staff = [
      { employee_id: 'DOC-001', full_name: 'Dr. Sarah Wilson', type: 'doctor', department: 'Cardiology', specialization: 'Cardiologist', base_salary: 5000, consultation_fee: 100, email: 'sarah@allcare.com' },
