                >
                    <tab.icon size={16}/> {tab.label}
                </button>
            ))}
        </div>
      </div>

      {/* --- DIRECTORY TAB --- */}
      {activeTab === 'directory' && (
        <div className="space-y-6 animate-in fade-in">
            <div className="flex flex-col lg:flex-row gap-4 justify-between items-center bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm">
                <div className="relative w-full lg:w-96">
