const Database = require('better-sqlite3');
const path = require('path');
const fs = require('fs');

const dbPath = process.env.DB_PATH || path.join(__dirname, '../../allcare.db');

// Ensure the directory exists
const dbDir = path.dirname(dbPath);
if (!fs.existsSync(dbDir)) {
  fs.mkdirSync(dbDir, { recursive: true });
}

const db = new Database(dbPath, { verbose: console.log });

const initDB = () => {
  db.pragma('journal_mode = WAL');

  // --- SMART RESET LOGIC ---
  let shouldReset = false;
  try {
    // Check if medical_staff has base_salary
    const staffTableCheck = db.prepare("SELECT name FROM sqlite_master WHERE type='table' AND name='medical_staff'").get();
    if (staffTableCheck) {
        const columns = db.pragma('table_info(medical_staff)');
        const hasBaseSalary = columns.some(col => col.name === 'base_salary');
        if (!hasBaseSalary) {
            console.log('⚠️  OUTDATED SCHEMA (Missing base_salary). Resetting database...');
            shouldReset = true;
        }
    }

    // Check if attendance table exists
    const attendanceCheck = db.prepare("SELECT name FROM sqlite_master WHERE type='table' AND name='attendance'").get();
    if (!attendanceCheck) {
        console.log('⚠️  OUTDATED SCHEMA (Missing HR tables). Resetting database...');
        shouldReset = true;
    }

  } catch (e) {
    console.log('Database check failed, proceeding with initialization.', e);
  }

  if (shouldReset) {
    const tables = [
      'users', 'patients', 'medical_staff', 'appointments', 'billing', 'billing_items',
      'lab_tests', 'lab_requests', 'nurse_services', 'operations_catalog', 'operations',
      'beds', 'admissions', 'inpatient_notes', 'departments', 'system_settings',
      'tax_rates', 'payment_methods', 'attendance', 'leaves', 'loans', 'financial_records', 'payroll'
    ];
    tables.forEach(t => db.exec(`DROP TABLE IF EXISTS ${t}`));
    console.log('✅ Database reset complete. Rebuilding tables...');
  }

  // --- SCHEMA DEFINITIONS ---
  const schema = `
    -- USERS & ROLES
    CREATE TABLE IF NOT EXISTS users (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      username TEXT UNIQUE NOT NULL,
      password TEXT NOT NULL,
      full_name TEXT NOT NULL,
      role TEXT NOT NULL,
      email TEXT,
      phone TEXT,
      is_active BOOLEAN DEFAULT 1,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    );

    -- PATIENTS
    CREATE TABLE IF NOT EXISTS patients (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      patient_id TEXT UNIQUE NOT NULL,
      full_name TEXT NOT NULL,
      phone TEXT NOT NULL,
      address TEXT,
      age INTEGER,
      gender TEXT,
      type TEXT DEFAULT 'outpatient',
      symptoms TEXT,
      medical_history TEXT,
      allergies TEXT,
      blood_group TEXT,
      emergency_contacts TEXT, 
      has_insurance BOOLEAN DEFAULT 0,
      insurance_details TEXT, 
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    );

    -- MEDICAL STAFF (HR Core)
    CREATE TABLE IF NOT EXISTS medical_staff (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      employee_id TEXT UNIQUE NOT NULL,
      full_name TEXT NOT NULL,
      type TEXT NOT NULL,
      department TEXT,
      specialization TEXT,
      base_salary REAL DEFAULT 0, -- NEW
      consultation_fee REAL DEFAULT 0,
      consultation_fee_followup REAL DEFAULT 0,
      consultation_fee_emergency REAL DEFAULT 0,
      is_available BOOLEAN DEFAULT 1,
      email TEXT,
      phone TEXT,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    );

    -- HR: ATTENDANCE
    CREATE TABLE IF NOT EXISTS attendance (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      staff_id INTEGER NOT NULL,
      date TEXT NOT NULL, -- YYYY-MM-DD
      status TEXT CHECK(status IN ('present', 'absent', 'late', 'half_day')) DEFAULT 'present',
      clock_in TEXT,
      clock_out TEXT,
      FOREIGN KEY(staff_id) REFERENCES medical_staff(id)
    );

    -- HR: LEAVES
    CREATE TABLE IF NOT EXISTS leaves (
