exports.getLoans = (req, res) => {
    try {
        const loans = db.prepare(`SELECT l.*, m.full_name FROM loans l JOIN medical_staff m ON l.staff_id = m.id ORDER BY l.request_date DESC`).all();
        res.json(loans);
    } catch(e) { res.status(500).json({error: e.message}); }
};

exports.createLoan = (req, res) => {
    const { staffId, amount, date, plan } = req.body;
    try {
        db.prepare('INSERT INTO loans (staff_id, amount, remaining_amount, request_date, repayment_plan, status) VALUES (?, ?, ?, ?, ?, ?)')
          .run(staffId, amount, amount, date, plan, 'pending');
        res.json({ success: true });
    } catch(e) { res.status(500).json({error: e.message}); }
};

exports.updateLoanStatus = (req, res) => {
    const { id } = req.params;
    const { status } = req.body;
    try {
        db.prepare('UPDATE loans SET status = ? WHERE id = ?').run(status, id);
        res.json({ success: true });
    } catch(e) { res.status(500).json({error: e.message}); }
};

// --- PAYROLL ---
exports.getPayroll = (req, res) => {
    try {
        const { month } = req.query; // YYYY-MM
        const sql = month 
            ? `SELECT p.*, m.full_name FROM payroll p JOIN medical_staff m ON p.staff_id = m.id WHERE p.month = ?`
            : `SELECT p.*, m.full_name FROM payroll p JOIN medical_staff m ON p.staff_id = m.id ORDER BY p.month DESC LIMIT 100`;
        const data = month ? db.prepare(sql).all(month) : db.prepare(sql).all();
        res.json(data);
    } catch(e) { res.status(500).json({error: e.message}); }
};

exports.generatePayroll = (req, res) => {
    const { month } = req.body; // YYYY-MM
    try {
        const tx = db.transaction(() => {
            // Delete existing payroll for this month to allow regeneration
            db.prepare('DELETE FROM payroll WHERE month = ?').run(month);

            const staffList = db.prepare('SELECT * FROM medical_staff WHERE is_available = 1').all();

            staffList.forEach(s => {
                // Calculate Bonuses & Fines for this month
                const startOfMonth = `${month}-01`;
                const endOfMonth = `${month}-31`;

                const financials = db.prepare(`
                    SELECT type, SUM(amount) as total 
                    FROM financial_records 
                    WHERE staff_id = ? AND date BETWEEN ? AND ? 
                    GROUP BY type
                `).all(s.id, startOfMonth, endOfMonth);

                const bonuses = financials.find(f => f.type === 'bonus')?.total || 0;
                const fines = financials.find(f => f.type === 'fine' || f.type === 'deduction')?.total || 0;

                // Check active loans for deduction (Simple logic: 10% of remaining loan or base salary cap)
                // In real app, this comes from repayment plan
                const activeLoan = db.prepare("SELECT * FROM loans WHERE staff_id = ? AND status = 'active' AND remaining_amount > 0").get(s.id);
                let loanDed = 0;
                if (activeLoan) {
                    loanDed = Math.min(activeLoan.remaining_amount, s.base_salary * 0.1); 
                    // Deduct from loan balance
                    db.prepare('UPDATE loans SET remaining_amount = remaining_amount - ? WHERE id = ?').run(loanDed, activeLoan.id);
                    if (activeLoan.remaining_amount - loanDed <= 0) {
                        db.prepare("UPDATE loans SET status = 'paid' WHERE id = ?").run(activeLoan.id);
                    }
                }

                const netSalary = (s.base_salary || 0) + bonuses - fines - loanDed;

                db.prepare(`
                    INSERT INTO payroll (staff_id, month, base_salary, total_bonuses, total_fines, loan_deduction, net_salary, status)
                    VALUES (?, ?, ?, ?, ?, ?, ?, 'generated')
                `).run(s.id, month, s.base_salary || 0, bonuses, fines, loanDed, netSalary);
            });
        });

        tx();
        res.json({ success: true });
    } catch(e) { res.status(500).json({error: e.message}); }
};
