## pages/Staff.tsx

Full overhaul of the Staff page to include the tabbed interface for Directory, Attendance, Leaves, Payroll, and Finance.

```tsx
import React, { useState, useEffect } from 'react';
import { Card, Button, Input, Select, Modal, Badge } from '../components/UI';
import { 
  Plus, Search, Filter, Mail, Phone, Briefcase, Lock, 
  LayoutGrid, List as ListIcon, User, Stethoscope, 
  CheckCircle, Clock, Shield, Calendar, DollarSign, Wallet, FileText, AlertCircle
} from 'lucide-react';
import { api } from '../services/api';
import { MedicalStaff, User as UserType } from '../types';
import { hasPermission, Permissions } from '../utils/rbac';

export const Staff = () => {
  const [activeTab, setActiveTab] = useState<'directory' | 'attendance' | 'leaves' | 'payroll' | 'finance'>('directory');
  const [staff, setStaff] = useState<MedicalStaff[]>([]);
  const [currentUser, setCurrentUser] = useState<UserType | null>(null);
  const [loading, setLoading] = useState(true);

  // Directory State
  const [searchTerm, setSearchTerm] = useState('');
  const [filterRole, setFilterRole] = useState('all');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [isStaffModalOpen, setIsStaffModalOpen] = useState(false);
  const [staffForm, setStaffForm] = useState<Partial<MedicalStaff>>({
    fullName: '', type: 'doctor', department: '', specialization: '', 
    baseSalary: 0, consultationFee: 0, email: '', phone: '', isAvailable: true
  });

  // HR Data States
  const [attendance, setAttendance] = useState<any[]>([]);
  const [leaves, setLeaves] = useState<any[]>([]);
  const [payroll, setPayroll] = useState<any[]>([]);
  const [financials, setFinancials] = useState<any[]>([]);
  const [loans, setLoans] = useState<any[]>([]);

  // HR Action States
  const [attendanceDate, setAttendanceDate] = useState(new Date().toISOString().split('T')[0]);
  const [payrollMonth, setPayrollMonth] = useState(new Date().toISOString().slice(0, 7)); // YYYY-MM

  // Modals
  const [isLeaveModalOpen, setIsLeaveModalOpen] = useState(false);
  const [leaveForm, setLeaveForm] = useState({ staffId: '', type: 'Sick', startDate: '', endDate: '', reason: '' });

  const [isFinanceModalOpen, setIsFinanceModalOpen] = useState(false);
  const [financeForm, setFinanceForm] = useState({ staffId: '', type: 'bonus', amount: '', date: new Date().toISOString().split('T')[0], reason: '' });

  const [isLoanModalOpen, setIsLoanModalOpen] = useState(false);
  const [loanForm, setLoanForm] = useState({ staffId: '', amount: '', date: new Date().toISOString().split('T')[0], plan: '' });

  const loadData = async () => {
    setLoading(true);
    try {
      const [staffData, userData] = await Promise.all([api.getStaff(), api.me()]);
      setStaff(Array.isArray(staffData) ? staffData : []);
      setCurrentUser(userData);
    } catch (e) { console.error(e); } 
    finally { setLoading(false); }
  };

  const loadTabData = async () => {
    if (activeTab === 'attendance') {
        const data = await api.getAttendance(attendanceDate);
        setAttendance(Array.isArray(data) ? data : []);
    } else if (activeTab === 'leaves') {
        const data = await api.getLeaves();
        setLeaves(Array.isArray(data) ? data : []);
    } else if (activeTab === 'payroll') {
        const data = await api.getPayroll(payrollMonth);
        setPayroll(Array.isArray(data) ? data : []);
    } else if (activeTab === 'finance') {
        const [fins, lns] = await Promise.all([api.getFinancialRecords(), api.getLoans()]);
        setFinancials(Array.isArray(fins) ? fins : []);
        setLoans(Array.isArray(lns) ? lns : []);
    }
  };

  useEffect(() => { loadData(); }, []);
  useEffect(() => { loadTabData(); }, [activeTab, attendanceDate, payrollMonth]);

  const handleCreateStaff = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
        await api.addStaff(staffForm as any);
        setIsStaffModalOpen(false);
        loadData();
    } catch (err: any) { alert(err.response?.data?.error || "Failed."); }
  };

  const handleMarkAttendance = async (staffId: number, status: string) => {
      const now = new Date().toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'});
      await api.markAttendance({ 
          staffId, 
          date: attendanceDate, 
          status, 
          clockIn: status === 'present' || status === 'late' ? now : null 
      });
      loadTabData();
  };

  const handleLeaveRequest = async (e: React.FormEvent) => {
      e.preventDefault();
      await api.requestLeave(leaveForm);
      setIsLeaveModalOpen(false);
      loadTabData();
  };

  const handleFinanceSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      await api.addFinancialRecord(financeForm);
      setIsFinanceModalOpen(false);
      loadTabData();
  };

  const handleLoanSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      await api.createLoan(loanForm);
      setIsLoanModalOpen(false);
      loadTabData();
  };

  const handleGeneratePayroll = async () => {
      if(!confirm(`Generate payroll for ${payrollMonth}? Previous data for this month will be overwritten.`)) return;
      await api.generatePayroll(payrollMonth);
      loadTabData();
  };

  const canManageHR = hasPermission(currentUser, Permissions.MANAGE_HR);

  // Filters
  const filteredStaff = staff.filter(s => {
    const matchesSearch = s.fullName.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesRole = filterRole === 'all' || s.type === filterRole;
    return matchesSearch && matchesRole;
