        </div>
      </div>

      {/* --- DIRECTORY TAB --- */}
      {activeTab === 'directory' && (
        <div className="space-y-6 animate-in fade-in">
            <div className="flex flex-col lg:flex-row gap-4 justify-between items-center bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm">
                <div className="relative w-full lg:w-96">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
                    <input type="text" placeholder="Search staff..." className="pl-10 w-full rounded-lg border-slate-300 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 py-2 text-sm" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
                </div>
                <div className="flex gap-3 w-full lg:w-auto">
                    <Select value={filterRole} onChange={e => setFilterRole(e.target.value)} className="w-40 !py-2 !text-sm"><option value="all">All Roles</option><option value="doctor">Doctors</option><option value="nurse">Nurses</option></Select>
                    {canManageHR && <Button onClick={() => setIsStaffModalOpen(true)} icon={Plus}>Add Staff</Button>}
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredStaff.map(person => (
                    <div key={person.id} className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm hover:shadow-md transition-all overflow-hidden p-5">
                        <div className="flex justify-between items-start mb-4">
                            <div className="h-12 w-12 rounded-full bg-slate-100 dark:bg-slate-700 flex items-center justify-center text-lg font-bold">{person.fullName.charAt(0)}</div>
                            <Badge color={person.isAvailable ? 'green' : 'gray'}>{person.isAvailable ? 'On Duty' : 'Off Duty'}</Badge>
