              <option value="doctor">Doctor</option><option value="nurse">Nurse</option><option value="technician">Technician</option><option value="admin_staff">Admin</option>
            </Select>
            <Input label="Department" required value={staffForm.department} onChange={e => setStaffForm({...staffForm, department: e.target.value})} />
          </div>
          <Input label="Base Salary ($)" type="number" required value={staffForm.baseSalary} onChange={e => setStaffForm({...staffForm, baseSalary: parseFloat(e.target.value)})} />
          <div className="pt-4 flex justify-end gap-3"><Button type="button" variant="secondary" onClick={() => setIsStaffModalOpen(false)}>Cancel</Button><Button type="submit">Create</Button></div>
        </form>
      </Modal>

      <Modal isOpen={isLeaveModalOpen} onClose={() => setIsLeaveModalOpen(false)} title="Request Leave">
          <form onSubmit={handleLeaveRequest} className="space-y-4">
              <Select label="Employee" required value={leaveForm.staffId} onChange={e => setLeaveForm({...leaveForm, staffId: e.target.value})}>
                  <option value="">Select Staff...</option>{staff.map(s => <option key={s.id} value={s.id}>{s.fullName}</option>)}
              </Select>
              <Select label="Type" value={leaveForm.type} onChange={e => setLeaveForm({...leaveForm, type: e.target.value})}><option value="Sick">Sick Leave</option><option value="Vacation">Vacation</option><option value="Unpaid">Unpaid</option></Select>
              <div className="grid grid-cols-2 gap-4">
                  <Input label="Start Date" type="date" required value={leaveForm.startDate} onChange={e => setLeaveForm({...leaveForm, startDate: e.target.value})} />
                  <Input label="End Date" type="date" required value={leaveForm.endDate} onChange={e => setLeaveForm({...leaveForm, endDate: e.target.value})} />
              </div>
              <Input label="Reason" required value={leaveForm.reason} onChange={e => setLeaveForm({...leaveForm, reason: e.target.value})} />
              <div className="pt-4 flex justify-end gap-3"><Button type="button" variant="secondary" onClick={() => setIsLeaveModalOpen(false)}>Cancel</Button><Button type="submit">Submit Request</Button></div>
          </form>
      </Modal>

      <Modal isOpen={isFinanceModalOpen} onClose={() => setIsFinanceModalOpen(false)} title="Add Adjustment">
          <form onSubmit={handleFinanceSubmit} className="space-y-4">
              <Select label="Employee" required value={financeForm.staffId} onChange={e => setFinanceForm({...financeForm, staffId: e.target.value})}>
                  <option value="">Select Staff...</option>{staff.map(s => <option key={s.id} value={s.id}>{s.fullName}</option>)}
              </Select>
              <Select label="Type" value={financeForm.type} onChange={e => setFinanceForm({...financeForm, type: e.target.value})}><option value="bonus">Bonus</option><option value="fine">Fine</option></Select>
              <Input label="Amount ($)" type="number" required value={financeForm.amount} onChange={e => setFinanceForm({...financeForm, amount: e.target.value})} />
              <Input label="Date" type="date" required value={financeForm.date} onChange={e => setFinanceForm({...financeForm, date: e.target.value})} />
              <Input label="Reason" required value={financeForm.reason} onChange={e => setFinanceForm({...financeForm, reason: e.target.value})} />
              <div className="pt-4 flex justify-end gap-3"><Button type="button" variant="secondary" onClick={() => setIsFinanceModalOpen(false)}>Cancel</Button><Button type="submit">Save Record</Button></div>
          </form>
      </Modal>

      <Modal isOpen={isLoanModalOpen} onClose={() => setIsLoanModalOpen(false)} title="Grant Loan">
          <form onSubmit={handleLoanSubmit} className="space-y-4">
              <Select label="Employee" required value={loanForm.staffId} onChange={e => setLoanForm({...loanForm, staffId: e.target.value})}>
                  <option value="">Select Staff...</option>{staff.map(s => <option key={s.id} value={s.id}>{s.fullName}</option>)}
              </Select>
              <Input label="Amount ($)" type="number" required value={loanForm.amount} onChange={e => setLoanForm({...loanForm, amount: e.target.value})} />
              <Input label="Date" type="date" required value={loanForm.date} onChange={e => setLoanForm({...loanForm, date: e.target.value})} />
              <Input label="Repayment Plan" placeholder="e.g. Deduct 10% monthly" value={loanForm.plan} onChange={e => setLoanForm({...loanForm, plan: e.target.value})} />
              <div className="pt-4 flex justify-end gap-3"><Button type="button" variant="secondary" onClick={() => setIsLoanModalOpen(false)}>Cancel</Button><Button type="submit">Grant Loan</Button></div>
          </form>
      </Modal>
    </div>
  );
};
